const express = require('express');
const sgMail = require('@sendgrid/mail');
require('dotenv').config();

const router = express.Router();

// Initialize SendGrid with API key from environment variable
const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY;

if (!SENDGRID_API_KEY) {
  console.error('ERROR: SENDGRID_API_KEY environment variable is not set');
  throw new Error('SendGrid API key is required. Please set SENDGRID_API_KEY environment variable.');
}

sgMail.setApiKey(SENDGRID_API_KEY);

async function sendEmailNotification(to, subject, text, html = null) {
  const fromEmail = process.env.SENDGRID_FROM_EMAIL || 'devops@example.com';
  
  const msg = {
    to: to,
    from: fromEmail,
    subject: subject,
    text: text,
    html: html || text
  };

  try {
    await sgMail.send(msg);
    return { success: true, message: 'Email sent successfully' };
  } catch (error) {
    console.error('Error sending email:', error.message);
    if (error.response) {
      console.error('SendGrid error details:', error.response.body);
    }
    throw error;
  }
}

router.post('/send-notification', async (req, res) => {
  try {
    const { to, subject, text, html } = req.body;

    if (!to || !subject || !text) {
      return res.status(400).json({
        error: 'Missing required fields: to, subject, and text are required'
      });
    }

    const result = await sendEmailNotification(to, subject, text, html);
    res.json(result);
  } catch (error) {
    res.status(500).json({
      error: 'Failed to send email',
      message: error.message
    });
  }
});

module.exports = { sendEmailNotification, router };